import { existsSync, readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { dirname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const packageRoot = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const sourceRoot = resolve(packageRoot, "..");
const manifestPath = join(
  sourceRoot,
  "client",
  "template-editor-runtime",
  "client",
  "template-editor-runtime",
  "manifest.js",
);
const outputPath = join(packageRoot, "src", "runtime", "template-editor-runtime.bundle.js");

function readUtf8(path) {
  return readFileSync(path, "utf8").replace(/^\uFEFF/, "");
}

if (!existsSync(manifestPath)) {
  if (existsSync(outputPath)) {
    console.log("Skipped runtime bundle rebuild because the ExamList source tree is not available.");
    process.exit(0);
  }

  throw new Error(`Could not find runtime manifest at ${manifestPath}`);
}

function getRequiredScripts(manifestSource) {
  const match = manifestSource.match(/const requiredScripts = Object\.freeze\(\[([\s\S]*?)\]\);/);

  if (!match) {
    throw new Error("Could not find requiredScripts in runtime manifest.");
  }

  return Array.from(match[1].matchAll(/"([^"]+\.js)"/g), (item) => item[1]);
}

const manifestSource = readUtf8(manifestPath);
const requiredScripts = getRequiredScripts(manifestSource);
const runtimeClientRoot = join(sourceRoot, "client", "template-editor-runtime");
const chunks = requiredScripts.map((assetPath) => {
  const sourcePath = join(runtimeClientRoot, assetPath);
  let source = readUtf8(sourcePath);

  if (assetPath === "client/features/template-editor/table-interaction.js") {
    source = source.replace(
      "    let clearTemplateEditorTableSelection = () => {};\n    let getTemplateEditorSelectedCell = () => null;\n    let getTemplateEditorTableCellTarget = () => null;",
      [
        "    let clearTemplateEditorTableSelection = () => {};",
        "    let getTemplateEditorActiveTableSelection = () => null;",
        "    let getTemplateEditorSelectedCell = () => null;",
        "    let getTemplateEditorSelectedTable = () => null;",
        "    let getTemplateEditorTableCellTarget = () => null;",
        "    let releaseTemplateEditorTableSelectionSession = () => {};",
        "    let startTemplateEditorTableSelectionSession = () => false;",
      ].join("\n"),
    );
  }

  return [
    "",
    `/* Source: ${assetPath} */`,
    source,
  ].join("\n");
});

const bundle = [
  "/*",
  " * Generated by scripts/build-runtime-bundle.js.",
  " * Source: ExamList client/template-editor-runtime manifest order.",
  " */",
  ...chunks,
  "",
  "const bundledTemplateEditorRuntime = globalThis.ExamListTemplateEditorRuntime || null;",
  "if (!bundledTemplateEditorRuntime) {",
  '  throw new Error("ExamList template editor runtime bundle did not register a runtime.");',
  "}",
  "",
  "export { bundledTemplateEditorRuntime };",
  "export default bundledTemplateEditorRuntime;",
  "",
].join("\n");

mkdirSync(dirname(outputPath), { recursive: true });
writeFileSync(outputPath, bundle, "utf8");

console.log(`Built ${outputPath} from ${requiredScripts.length} runtime scripts.`);
